/**
 *
 * @param Regexp: 需要校验的正则表达式
 * @param text：需要匹配的内容
 */
declare const regex: (regexp: IRegType, text: string) => boolean;
declare type IRegType = 'emailRegexp' | 'phoneRegexp' | 'fixPhone' | 'idRegexp' | 'ipv4Regexp' | 'chineseRegexp' | 'qqRegexp' | 'chinesePostcodeRegexp' | 'usPostcodeRegexp' | 'ukPostcodeRegexp' | 'carNumberRegexp' | 'accountRegexp' | 'rgbRegexp' | 'rgbaRegexp' | 'numberRegexp' | 'hslRegexp' | 'hslaRegexp';
export default regex;
